+TEST(IVDescriptorsTest, UnsupportedFindLastPhi) {
+  // Parse the module.
+  LLVMContext Context;
+
+  // This is a constructed example for the test, but it's based on a loop like:
+  //  int result = default_val;
+  //  for (int i = 0; i < N; ++i) {
+  //    if (cond_0) {
+  //      if (cond_1)
+  //        result = v1;
+  //    } else {
+  //      if (cond_1)
+  //        result = v2;
+  //    }
+  //  }
+  //  return result;
+  std::unique_ptr<Module> M = parseIR(Context, R"(
+    define i64 @unsupported_find_last_phi(
+      i64 %v1, i64 %v2, i64 %default_val, i64 %N, i1 %cond.0, i1 %cond.1
+    ) {
+      entry:
+        br label %loop
+
+      loop:
+        %result.0 = phi i64 [ %default_val, %entry ], [ %result.3, %for.inc ]
+        %idx = phi i64 [ 0, %entry ], [ %inc, %for.inc ]
+        br i1 %cond.0, label %outer.if.then, label %if.else
+
+      outer.if.then:
+        br i1 %cond.1, label %inner.if.then.0, label %inner.if.end.0
+
+      inner.if.then.0:
+        br label %inner.if.end.0
+
+      inner.if.end.0:
+        %result.1 = phi i64
+          [ %v1, %inner.if.then.0 ], [ %result.0, %outer.if.then ]
+        br label %for.inc
+
+      if.else:
+        br i1 %cond.1, label %inner.if.then.1, label %inner.if.end.1
+
+      inner.if.then.1:
+        br label %inner.if.end.1
+
+      inner.if.end.1:
+        %result.2 = phi i64 [ %v2, %inner.if.then.1 ], [ %result.0, %if.else ]
+        br label %for.inc
+
+      for.inc:
+        %result.3 = phi i64
+          [ %result.1, %inner.if.end.0 ], [ %result.2, %inner.if.end.1 ]
+        %inc = add nsw i64 %idx, 1
+        %cmp = icmp slt i64 %idx, %N
+        br i1 %cmp, label  %loop, label %exit
+
+      exit:
+        ret i64 %result.3
+    })");
+
+  runWithLoopInfoAndSE(*M, "unsupported_find_last_phi",
+                       [&](Function &F, LoopInfo &LI, ScalarEvolution &SE) {
+                         Function::iterator FI = F.begin();
+                         // First basic block is entry - skip it.
+                         BasicBlock *Header = &*(++FI);
+                         assert(Header->getName() == "loop");
+                         Loop *L = LI.getLoopFor(Header);
+                         EXPECT_NE(L, nullptr);
+                         BasicBlock::iterator BBI = Header->begin();
+                         PHINode *Phi = dyn_cast<PHINode>(&*BBI);
+                         EXPECT_NE(Phi, nullptr);
+                         EXPECT_EQ(Phi->getName(), "result.0");
+                         RecurrenceDescriptor Rdx;
+                         bool IsRdxPhi =
+                             RecurrenceDescriptor::isReductionPHI(Phi, L, Rdx);
+                         EXPECT_FALSE(IsRdxPhi);
+                       });
+}

description:
This patch extends the support added in #158088 to loops where the assignment is non-speculatable (e.g. a conditional load or divide).

For example, the following loop can now be vectorized:

```
int simple_csa_int_load(
  int* a, int* b, int default_val, int N, int threshold)
{
  int result = default_val;
  for (int i = 0; i < N; ++i)
    if (a[i] > threshold)
      result = b[i];
  return result;
}
```

It does this by extending the recurrence matching from only looking for selects, to include phis where all operands are the header phi, except for one which can be an arbitrary value outside the recurrence.

---

Reverts llvm/llvm-project#180275 (original PR: #178862)

Additional type legalization for `ISD::VECTOR_FIND_LAST_ACTIVE` was added in #180290, which should resolve the backend crashes on x86.
